mapper.select:
SELECT LOG_CD , SEND_TYPE , CASE SEND_TYPE WHEN 'E' THEN '이메일' WHEN 'S' THEN 'SMS' WHEN 'A' THEN '알림톡' ELSE SEND_TYPE END AS SEND_TYPE_NM , RECV_NM , RECV_ADDR , SEND_TITLE , SEND_RSLT , ERR_MSG , REF_CD , CRE_USR_CD , DATE_FORMAT(CRE_DTM, '%Y-%m-%d %H:%i:%s') AS CRE_DTM FROM TB_SEND_LOG WHERE 1=1
AND SEND_TYPE = #{searchSendType}
AND SEND_RSLT = #{searchRslt}
AND ( RECV_NM LIKE CONCAT('%', #{searchKeyword}, '%') OR RECV_ADDR LIKE CONCAT('%', #{searchKeyword}, '%') OR SEND_TITLE LIKE CONCAT('%', #{searchKeyword}, '%') )
ORDER BY CRE_DTM DESC LIMIT 200
